/// <summary>
/// This method shows only the export type TERMO Number details in the lookup for TERMO Number
/// </summary>
/// <param name="sender">FormControl</param>
/// <param name="e">FormControlEventArgs</param>
[FormControlEventHandler(formControlStr(SalesEditLines, SalesParmTable_ETGMotherTERMONumber), FormControlEventType::Lookup)]
public static void SalesParmTable_ETGMotherTERMONumber_OnLookup(FormControl sender, FormControlEventArgs e)
{
    ETGTERMONumberTable::lookupTERMONumberTable(sender, ETGImportOrExport::Export);
    FormControlCancelableSuperEventArgs cancelSuperEventArgs = e as FormControlCancelableSuperEventArgs;
    cancelSuperEventArgs.CancelSuperCall();
}

