    /// <summary>
    /// Event handler for the Activated event of the SalesParmTable data source
    /// on the SalesEditLines form.
    /// </summary>
    [FormDataSourceEventHandler(formDataSourceStr(SalesEditLines, SalesParmTable), FormDataSourceEventType::Activated)]
    public static void SalesParmTable_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
    {

        if (ETG_Parameters::find().ETGDocumentDate == NoYes::Yes)
        {
            sender.object(fieldNum(SalesParmTable, DocumentDate)).mandatory(true);
        }
        else
        {
            sender.object(fieldNum(SalesParmTable, DocumentDate)).mandatory(false);
        }
    }
